import React, { useState } from 'react';
import { Plus } from 'lucide-react';

interface TodoInputFormProps {
  onCreateTodo?: (title: string) => void;
}

export default function TodoInputForm({ onCreateTodo }: TodoInputFormProps) {
  const [title, setTitle] = useState('');

  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const nextTitle = title.trim();
    if (!nextTitle) return;
    onCreateTodo?.(nextTitle);
    setTitle('');
  };

  return (
    <form onSubmit={handleSubmit} className="flex gap-3 rounded-2xl bg-white p-3 shadow-sm ring-1 ring-slate-200">
      <input value={title} onChange={(event) => setTitle(event.target.value)} placeholder="Add a new todo" className="min-w-0 flex-1 rounded-xl border border-slate-200 px-4 py-3 outline-none focus:border-blue-500" />
      <button type="submit" className="inline-flex items-center gap-2 rounded-xl bg-blue-600 px-4 py-3 font-medium text-white hover:bg-blue-700">
        <Plus className="h-4 w-4" /> Add
      </button>
    </form>
  );
}

import React from 'react';
import type { Todo } from '../types/todo';

interface TodoListPanelProps {
  todos?: Todo[];
  onToggleTodo?: (id: string) => void;
}

export default function TodoListPanel({ todos = [], onToggleTodo }: TodoListPanelProps) {
  if (!todos.length) {
    return <div className="rounded-2xl border border-dashed border-slate-300 bg-white p-8 text-center text-slate-500">No todos yet</div>;
  }

  return (
    <div className="space-y-3">
      {todos.map((todo) => (
        <button key={todo.id} onClick={() => onToggleTodo?.(todo.id)} className="flex w-full items-center justify-between rounded-2xl bg-white p-4 text-left shadow-sm ring-1 ring-slate-200 hover:ring-blue-200">
          <span className={todo.completed ? 'text-slate-400 line-through' : 'text-slate-900'}>{todo.title}</span>
          <span className="text-sm text-slate-400">{todo.completed ? 'Done' : 'Todo'}</span>
        </button>
      ))}
    </div>
  );
}
